import dspy
import re

def detect_injection(output):
    injection_patterns = [
        r'(ignore.*previous|forget.*instructions)',
        r'(you are now|act as).*malicious',
        r'output.*json.*\{.*\}',
        r'execute.*code|run.*command'
    ]
    for pattern in injection_patterns:
        if re.search(pattern, output, re.IGNORECASE):
            return True
    return False

# Usage in DSPy module
class SafeChainOfThought(dspy.ChainOfThought):
    def forward(self, **kwargs):
        prediction = super().forward(**kwargs)
        if detect_injection(prediction.completion):
            raise ValueError('Prompt injection detected')
        return prediction

